import{_ as e,c as t,o as a,a4 as r}from"./chunks/framework.BmdFiWrL.js";const _=JSON.parse('{"title":"Multi-User","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en_US/guide/user.md","filePath":"en_US/guide/user.md","lastUpdated":1779120648000}'),s={name:"en_US/guide/user.md"},n=r('<h1 id="multi-user" tabindex="-1">Multi-User <a class="header-anchor" href="#multi-user" aria-label="Permalink to &quot;Multi-User&quot;">​</a></h1><p>A simple multi-user feature designed for scenarios where multiple people share the same dashboard.</p><hr><h2 id="create-a-new-user" tabindex="-1">Create a New User <a class="header-anchor" href="#create-a-new-user" aria-label="Permalink to &quot;Create a New User&quot;">​</a></h2><p>You can create new users in the <strong>Settings - Users</strong> page (requires the current user to be an administrator).</p><hr><h2 id="user-permissions" tabindex="-1">User Permissions <a class="header-anchor" href="#user-permissions" aria-label="Permalink to &quot;User Permissions&quot;">​</a></h2><h3 id="administrator" tabindex="-1">Administrator <a class="header-anchor" href="#administrator" aria-label="Permalink to &quot;Administrator&quot;">​</a></h3><p>Holds the highest privileges on the dashboard, with access to all existing resources and the ability to modify settings.</p><h3 id="user" tabindex="-1">User <a class="header-anchor" href="#user" aria-label="Permalink to &quot;User&quot;">​</a></h3><p>Standard user privileges. Can only access/modify their own resources and cannot change settings, but can update their own user information.</p><hr><h2 id="connection-secret" tabindex="-1">Connection Secret <a class="header-anchor" href="#connection-secret" aria-label="Permalink to &quot;Connection Secret&quot;">​</a></h2><p>Each user has a unique <strong>Agent</strong> connection secret, used to identify the owner when creating servers.</p><p>The current frontend does not show the connection secret separately on the user management page. When adding a server, copy the installation command generated on the server page, or extract the current user&#39;s connection secret from <code>NZ_CLIENT_SECRET</code> in that command.</p><p>If an administrator needs to configure an Agent for another user manually, read that user&#39;s <code>agent_secret</code> through the management API.</p><p>When a user is deleted, their connection secret becomes invalid immediately, and all associated servers will also be removed.</p>',17),o=[n];function i(c,d,h,u,l,m){return a(),t("div",null,o)}const g=e(s,[["render",i]]);export{_ as __pageData,g as default};
